class Solution {
public:
    vector<int> shortestAlternatingPaths(int n, vector<vector<int>>& redEdges, vector<vector<int>>& blueEdges) {
        vector<vector<int>> red(n), blue(n);
        for (auto e : redEdges) red[e[0]].push_back(e[1]);
        for (auto e : blueEdges) blue[e[0]].push_back(e[1]);
        vector<int> res(n, -1);
        queue<pair<int, int>> q;
        q.push({0, 0}); q.push({0, 1});
        res[0] = 0;
        int step = 0;
        while (!q.empty()) {
            int sz = q.size();
            for (int i = 0; i < sz; i++) {
                int node = q.front().first, color = q.front().second;
                q.pop();
                if (color == 0) {
                    for (int next : blue[node]) {
                        if (res[next] == -1) {
                            res[next] = step + 1;
                            q.push({next, 1});
                        }
                    }
                } else {
                    for (int next : red[node]) {
                        if (res[next] == -1) {
                            res[next] = step + 1;
                            q.push({next, 0});
                        }
                    }
                }
            }
            step++;
        }
        return res;
    }
};
